import type EsriColor from "../../../Color.js";
import type { JSONSupport } from "../../../core/JSONSupport.js";
import type { ColorLike } from "../../../Color.js";

/** @since 5.0 */
export interface ColorClassBreakInfoProperties extends Partial<Pick<ColorClassBreakInfo, "label" | "maxValue" | "minValue">> {
  /**
   * The color used to colorize the points where
   *           values are between the `minValue` and `maxValue` of the break.
   *
   * @since 5.0
   */
  color?: ColorLike;
}

/** @since 5.0 */
export default class ColorClassBreakInfo extends JSONSupport {
  constructor(properties?: ColorClassBreakInfoProperties);
  /**
   * The color used to colorize the points where
   *           values are between the `minValue` and `maxValue` of the break.
   *
   * @since 5.0
   */
  get color(): EsriColor;
  set color(value: ColorLike);
  /**
   * The label used to describe point in the break.
   *
   * @since 5.0
   */
  accessor label: string | null | undefined;
  /**
   * The maximum value of the break.
   *
   * @default 0
   * @since 5.0
   */
  accessor maxValue: number;
  /**
   * The minimum value of the break.
   *
   * @default 0
   * @since 5.0
   */
  accessor minValue: number;
}